def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.15:
            for a in range(1, 10):
                factor = (np.sin(ratio * a * np.pi) + 1) * (a ** 1.7)
                decay = np.exp(-ratio * a)
                score += factor * decay
            if int((capacity + item) * 3) % 7 == 0:
                score *= 0.88
            if score > 8:
                score /= 4
        elif 0.15 <= ratio < 0.4:
            prod = 1
            for n in range(1, int(capacity//3) + 2):
                prod *= (n + ratio)
                if prod > 1e6:
                    prod %= 2000
                    break
            score += np.log1p(prod) * (ratio * 5)
            if (int(capacity) % 6 == 0) and (round(item, 2) % 0.2 == 0):
                score += 4.5
            else:
                score -= 0.7
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) ** 1.3 * (x ** 2)
            score += extra / 6
        elif 0.4 <= ratio <= 0.75:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 4) / (m + 2)
                score += increment
            remainder = capacity - item
            if remainder < 1.5:
                score += 7 + remainder * 1.2
            else:
                score -= remainder * 0.6
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.15
        elif 0.75 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.75) ** p) * (p ** 1.5) * ((-1)**p)
            score = base_penalty * 12
            if capacity < item * 1.05:
                score += 12
            if (int(capacity * 8) % 5 == 0) and (int(item * 12) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.5
                score += 3
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 3) * ((-1)**(q+1))
            score = penalty * 20
            if capacity < item * 1.3:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 14) % 3 == 0):
                score -= 7
            for z in range(3, 7):
                score += ((diff / z) % 1) * (z * 1.7) * ((-1)**z)
            if score < 0:
                score = abs(score) * 0.5
        if capacity > 200:
            score /= (np.sqrt(capacity) + 1)
        elif capacity < 10:
            score *= 2.1
        if abs(score) > 1200:
            score = np.sign(score) * 1200
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 1
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 80))
        median_val = np.median(finite_priorities)
        max_val = np.max(finite_priorities)
        fill_value = max_val * (15 + top_ratio_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_val if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if priorities[idx] < 0:
            adjustment = 0
            for r in range(1, 5):
                adjustment += ((idx + r) ** 2) * np.tanh(priorities[idx] / (r + 1))
            priorities[idx] += adjustment * 0.05
    return priorities
